// Monta o id da linha em cabin_media a partir de (categoria, variante, conta).
// Padrões descobertos em WF_Upload_Cabin_Media:
//   experience resource:   id = `${categoria}${conta}`                       ex: cabines__varanda_experience + _formulario
//   marketing: id = `marketing__${slug}__${variante}${conta}`    ex: marketing__navio_do_wesley_safadao__video + _bdr
// Para marketing, a `categoria` que vem do caller pode ser tanto `marketing__<slug>`
// quanto `material_marketing_<conta>` (como está gravado no banco). Tratamos ambos.
const t = $input.first().json;
const categoria = String(t.categoria || '').trim();
const variante = t.variante === null || t.variante === undefined ? null : String(t.variante).trim() || null;
const conta = String(t.conta || '').trim();

const CONTAS_VALIDAS = ['_formulario', '_whatsapp', '_bdr'];
if (!CONTAS_VALIDAS.includes(conta)) {
  throw new Error(`conta invalida: '${conta}'. Use ${CONTAS_VALIDAS.join('|')}`);
}
if (!categoria) throw new Error('categoria vazia');

let id;
if (categoria.startsWith('cabines__')) {
  id = `${categoria}${conta}`;
} else if (categoria.startsWith('marketing__')) {
  if (!variante) throw new Error('variante obrigatoria para marketing (banner|video)');
  id = `${categoria}__${variante}${conta}`;
} else if (categoria.startsWith('material_marketing')) {
  // Categoria no formato como está gravada no banco (material_marketing_<conta>).
  // Nesse caso o caller precisa mandar tambem o slug via `variante` no formato `${slug}__${banner|video}`.
  // Mantido apenas como fallback — preferencia é categoria=marketing__<slug>.
  throw new Error('Para marketing, passe categoria=marketing__<slug> e variante=banner|video');
} else {
  throw new Error(`prefixo de categoria desconhecido: '${categoria}'`);
}

return [{ json: { id, categoria, variante, conta } }];

// Saida final da tool buscar_midia_cabine
const rows = $input.all().map(i => i.json);
const req = $('Montar ID').first().json;

if (!rows.length || !rows[0].id) {
  return [{
    json: {
      encontrado: false,
      motivo: 'media_nao_cadastrada',
      id_tentado: req.id,
      categoria: req.categoria,
      variante: req.variante,
      conta: req.conta
    }
  }];
}

const r = rows[0];
return [{
  json: {
    encontrado: true,
    id: r.id,
    categoria: r.categoria,
    variante: r.variante,
    label: r.label,
    asset_url: r.asset_url,
    whatsapp_id: r.whatsapp_id,
    tem_whatsapp_id: !!r.whatsapp_id
  }
}];
